import{getAssetFromKV,mapRequestToAsset}from"@cloudflare/kv-asset-handler";let DEBUG=!1;async function handleEvent(t){var e,s=new URL(t.request.url),n={};try{return DEBUG&&(n.cacheControl={bypassCache:!0}),1<s.pathname.length&&s.pathname.endsWith("/")?(e=s.pathname.slice(0,-1)+s.search,Response.redirect(e,301)):await getAssetFromKV(t,n)}catch(e){if(!DEBUG)try{var r=await getAssetFromKV(t,{mapRequestToAsset:e=>new Request(new URL(e.url).origin+"/404.html",e)});return new Response(r.body,{...r,status:404})}catch(e){}return new Response(e.message||e.toString(),{status:500})}}function handlePrefix(s){return e=>{var e=mapRequestToAsset(e),t=new URL(e.url);return t.pathname=t.pathname.replace(s,"/"),new Request(t.toString(),e)}}addEventListener("fetch",t=>{try{t.respondWith(handleEvent(t))}catch(e){if(DEBUG)return t.respondWith(new Response(e.message||e.toString(),{status:500}));t.respondWith(new Response("Internal Error",{status:500}))}});